<template><div class="panel"><div class="section-head"><div><h2>字典管理</h2><p>统一维护系统枚举与展示标签。</p></div><el-button type="primary" @click="openType()">新增类型</el-button></div><el-row :gutter="20"><el-col :span="9"><el-table :data="types" highlight-current-row @current-change="selectType"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column label="操作"><template #default="s"><el-button link @click.stop="openType(s.row)">编辑</el-button><el-button link type="danger" @click.stop="removeType(s.row)">删除</el-button></template></el-table-column></el-table></el-col><el-col :span="15"><div class="section-head"><strong>{{current?.name||'请选择字典类型'}}</strong><el-button :disabled="!current" @click="openData()">新增数据</el-button></div><el-table :data="dataRows"><el-table-column prop="label" label="标签"/><el-table-column prop="dictValue" label="值"/><el-table-column prop="sortOrder" label="排序"/><el-table-column label="操作"><template #default="s"><el-button link @click="openData(s.row)">编辑</el-button><el-button link type="danger" @click="removeData(s.row)">删除</el-button></template></el-table-column></el-table></el-col></el-row><el-dialog v-model="typeVisible" title="字典类型"><el-form label-width="90px"><el-form-item label="编码"><el-input v-model="typeForm.code"/></el-form-item><el-form-item label="名称"><el-input v-model="typeForm.name"/></el-form-item><el-form-item label="说明"><el-input v-model="typeForm.description"/></el-form-item><el-form-item label="启用"><el-switch v-model="typeForm.enabled"/></el-form-item></el-form><template #footer><el-button @click="typeVisible=false">取消</el-button><el-button type="primary" @click="saveType">保存</el-button></template></el-dialog><el-dialog v-model="dataVisible" title="字典数据"><el-form label-width="90px"><el-form-item label="标签"><el-input v-model="dataForm.label"/></el-form-item><el-form-item label="值"><el-input v-model="dataForm.dictValue"/></el-form-item><el-form-item label="排序"><el-input-number v-model="dataForm.sortOrder"/></el-form-item><el-form-item label="启用"><el-switch v-model="dataForm.enabled"/></el-form-item></el-form><template #footer><el-button @click="dataVisible=false">取消</el-button><el-button type="primary" @click="saveData">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessageBox}from'element-plus';import http from'../api/http';const types=ref([]),dataRows=ref([]),current=ref(null),typeVisible=ref(false),dataVisible=ref(false),typeForm=reactive({id:null,code:'',name:'',description:'',enabled:true}),dataForm=reactive({id:null,typeCode:'',label:'',dictValue:'',sortOrder:0,enabled:true});async function loadTypes(){types.value=(await http.get('/system/dictionaries/types')).data}/** 选择字典类型。 */async function selectType(row){if(!row)return;current.value=row;dataRows.value=(await http.get('/system/dictionaries/data',{params:{typeCode:row.code}})).data}/** 打开类型窗口。 */function openType(row){Object.assign(typeForm,row?{...row}:{id:null,code:'',name:'',description:'',enabled:true});typeVisible.value=true}/** 保存类型。 */async function saveType(){typeForm.id?await http.put(`/system/dictionaries/types/${typeForm.id}`,typeForm):await http.post('/system/dictionaries/types',typeForm);typeVisible.value=false;await loadTypes()}/** 删除类型。 */async function removeType(row){await ElMessageBox.confirm(`确认删除「${row.name}」？`);await http.delete(`/system/dictionaries/types/${row.id}`);await loadTypes()}/** 打开字典数据窗口。 */function openData(row){Object.assign(dataForm,row?{...row}:{id:null,typeCode:current.value.code,label:'',dictValue:'',sortOrder:0,enabled:true});dataVisible.value=true}/** 保存字典数据。 */async function saveData(){dataForm.id?await http.put(`/system/dictionaries/data/${dataForm.id}`,dataForm):await http.post('/system/dictionaries/data',dataForm);dataVisible.value=false;await selectType(current.value)}/** 删除字典数据。 */async function removeData(row){await http.delete(`/system/dictionaries/data/${row.id}`);await selectType(current.value)}onMounted(loadTypes)</script>
